class TweetCounts {
public:
    TweetCounts() {

    }

    void recordTweet(string tweetName, int time) {
        tweetCounts[tweetName].push_back(time);
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        int chunkSize = (freq == "minute") ? 60 : (freq == "hour") ? 3600 : 86400;
        int chunks = (endTime - startTime) / chunkSize + 1;
        vector<int> res(chunks, 0);
        for (int time : tweetCounts[tweetName]) {
            if (startTime <= time && time <= endTime) {
                res[(time - startTime) / chunkSize]++;
            }
        }
        return res;
    }
private:
    unordered_map<string, vector<int>> tweetCounts;
};
```
